import style from "./index.module.scss"

let id = 0
export default class Select extends HTMLElement {
  constructor() {
    super();
    const shadowRoot = this.attachShadow({ mode: 'open' });
    const sheet = new CSSStyleSheet();
    sheet.replaceSync(style);
    shadowRoot.adoptedStyleSheets = [sheet];
    let listboxId = `select-listbox-${++id}`
    let labelId = `select-listbox-${++id}`
    shadowRoot.innerHTML = `
      <div class="select">
        <div 
          class="trigger" 
          tabindex="0" 
          role="combobox" 
          aria-haspopup="listbox"
          aria-expanded="false"
          aria-labelledby=${labelId}
          aria-controls=${listboxId}
        >
          <span class="label" id=${labelId}>
            <slot name="trigger">about me</slot>
          </span>
          <span class="icon">
            <huanlin-icon name="arrow-down"></huanlin-icon>
          </span>
        </div>
        <div class="popup" role="listbox" id="${listboxId}">
          <slot></slot>
        </div>
      </div>
    `
  }

  handleTriggerClick = e => {
    const popup = this.shadowRoot.querySelector(".popup")
    const active = popup.classList.contains("active")
    if (active) {
      popup.classList.remove("active")
    } else {
      popup.classList.add("active")
    }
  }
  handlePopoverClick = e => {
    // handle popup
    const option = e.target.closest("huanlin-option")
    option && this.setActiveOption(option.name)
    this.focusTrigger()
    this.hide()
  }
    
  willLoad = () => {
    this.triggerEle = this.shadowRoot.querySelector(".trigger")
    this.triggerEle?.addEventListener("click", this.handleTriggerClick)
    this.popoverEle = this.shadowRoot.querySelector(".popup")
    this.popoverEle?.addEventListener("click", this.handlePopoverClick)
    this.triggerEle?.addEventListener("keydown", this.handleKeyboard)
    this.popoverEle?.addEventListener("keydown", this.handleOptionArrow)
    this.labelEle = this.shadowRoot.querySelector(".label")
    this.addEventListener("keydown", this.handleCloseKeyboard)
    document.addEventListener("click", this.handleClickOutside)
  }
  connectedCallback() {
    this.classList.add("hydrated")
    setTimeout(() => {
      this.willLoad()
    })
  }
  static get observedAttributes() {
    return ["value"];
  }
  attributeChangedCallback(name, oldValue, newValue) {
    if (name === "value") this.setActiveOption(newValue)
  } 
  disconnectedCallback() {
    this.triggerEle?.removeEventListener("click", this.handleTriggerClick)
    this.popoverEle?.removeEventListener("click", this.handlePopoverClick)
    document.removeEventListener("click", this.handleClickOutside)
    this.removeEventListener("keydown", this.handleCloseKeyboard)
    this.popoverEle?.removeEventListener("keydown", this.handleOptionArrow)
  }

  setActiveOption = (name) => {
    // set active option
    customElements.whenDefined("huanlin-option").then(() => {
      const optionList = Array.from(this.querySelectorAll("huanlin-option"))
      let option 
      optionList.forEach(opt => {
        if (opt.name === name) {
          option = opt
          opt.setAttribute("active", "")
        } else {
          opt.removeAttribute("active")
        }
      })
      // update trigger innerHTML
      this.setLabel(option.innerHTML)
    })
  }

  setLabel = async (value) => {
    this.labelEle && (this.labelEle.innerHTML = value)
  }

  handleOptionArrow = e => {
    if (e.key === "ArrowDown") {
      const options = this.getOptions()
      const index = options.indexOf(e.target)
      const current = index + 1
      if (current < 0 || current >= options.length) return
      options[current].setFocus()
    } else if (e.key === "ArrowUp") {
      const options = this.getOptions()
      const index = options.indexOf(e.target)
      const current = index - 1
      if (current < 0 || current >= options.length) return
      options[current].setFocus()
    } else if (e.key === "Enter") {
      this.setActiveOption(e.target.name) 
      e.target.click()
      this.hide()
      this.focusTrigger()
    }
  }

  getOptions = () => {
    return Array.from(this.querySelectorAll("huanlin-option"))
  }

  handleCloseKeyboard = e => {
    if (e.key === "Escape") {
      this.hide()
      this.focusTrigger()
    } else if (e.key === "Tab" || e.shiftKey && e.key === "Tab") {
      this.hide()
    }
  }

  focusTrigger = () => {
    this.triggerEle.focus()
  }

  handleKeyboard = e => {
    if (["ArrowDown", " ", "Enter"].includes(e.key)) {
      this.show()
      const options = this.getOptions()
      options.length && options[0].setFocus()
    }
  }

  handleClickOutside = e => {
    if(!e.composedPath().includes(this)){
      this.popoverEle.classList.remove("active");
    }
  }

  show = () => {
    const popup = this.popoverEle
    this.triggerEle.setAttribute("aria-expanded", true)
    popup.classList.add("active")
  }

  hide = () => {
    const popup = this.popoverEle
    this.triggerEle.setAttribute("aria-expanded", false)
    popup.classList.remove("active")
  }
}
